#include<bits/stdc++.h>
using namespace std;
int dx[] = {0, 1, 0, -1};
int dy[] = {1, 0, -1, 0};
char c[502][502];
int ant, n, m;
void dfs(int x,int y)
{
    c[x][y]='X';
    for(int i=0;i<4;i++)
    {
        int nx=dx[i]+x;
        int ny=dy[i]+y;
        if(nx>0&&nx<=n&&ny>0&&ny<=m&&c[nx][ny]=='R')
            dfs(nx,ny);
    }
    return ;
}
int main() {
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= m; j++) {
			cin >> c[i][j];
		}
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= m; j++) {
			if (c[i][j] == 'R') {
				dfs(i, j);
				ant++;
			}
		}
	}
	cout<<ant;
	return 0;
}
